      const result = matcher.matchFilePath('dist/build.js', fileMatcher.patterns);

      expect(result).toBe(false);
    });

    it('should support multiple patterns', () => {
      const fileMatcher = createFilePathMatcher(['src/**/*.ts', 'tests/**/*.test.ts']);

