  /**
   * Clean up resources
   */
  async destroy(): Promise<void> {
    this.logger.info('Destroying Swarm API');

    // Destroy all swarms
    for (const [swarmId, swarm] of this.swarms) {
      try {
        await swarm.destroy();
      } catch (error) {
        this.logger.error('Error destroying swarm', { swarmId, error });
      }
    }

    this.swarms.clear();
  }
