      updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      metadata TEXT DEFAULT '{}'
    );
  `,
  agents: `
    CREATE TABLE IF NOT EXISTS agents (
      id TEXT PRIMARY KEY,
      swarm_id TEXT,
      name TEXT NOT NULL,
      type TEXT NOT NULL,
      role TEXT,
      capabilities TEXT DEFAULT '[]',
